     3→import { assertObject, flatRecordRecords, objectEntries } from '../helpers/object-utils';
     4→import { capitalize } from '../helpers/string-utils';
     5→import { Cache } from './cache';
     6→import { Context } from './context';
     7→import { GLOBAL_APP_SESSION_ID } from './helpers';
     8→import { Hooks } from './hooks';
     9→import {
    10→  type CombineSlicesContext,
    11→  type CombineSlicesState,
    12→  type MachineAction,
    13→  type MachineConfig,
    14→  type MachineMetadata,
    15→  type MachineReducer,
    16→  type MachineSelectors,
    17→  type MachineSlices,
    18→  type MachineState,
    19→  type MachineUserID,
    20→  METADATA_FIELD_NAME,
    21→  type SliceContext,
    22→  type StateMachine,
    23→  type StringTypes,
    24→  type UpsertMetadataOperation,
    25→} from './models';
    26→import { Slices } from './slice';
    27→import { Store } from './store';
    28→
    29→export namespace Machine {
    30→  export function GetSelectorsWrapper(params: { selectors: MachineSelectors<any> | undefined }) {
    31→    const { selectors } = params;
    32→    const selectorEntries = selectors ? objectEntries(selectors) : null;
    33→    return function injectSelectorValues(state: MachineState) {
    34→      if (!selectorEntries?.length) return state;
    35→      return produce(state, (draft) => {
    36→        selectorEntries.forEach(([key, fn]) => {
    37→          draft[key] = fn(draft);
    38→        });
    39→      });
    40→    };
    41→  }
    42→
    43→  export function UpsertStateMetadata(params: {
    44→    operation: UpsertMetadataOperation;
    45→    userID: MachineUserID;
    46→    mappedSlices: Slices.SlicesMap;
    47→    currentSessionID: string;
    48→  }) {
    49→    const { operation, userID, mappedSlices, currentSessionID } = params;
    50→
    51→    if (operation.op === 'update') {
    52→      const { originActionType, state, override } = operation;
    53→      const previousMetadata = state[METADATA_FIELD_NAME] as MachineMetadata;
    54→
    55→      assertObject(previousMetadata, 'UpsertStateMetadata failed. No metadata found in state.');
    56→
    57→      const meta = {
    58→        /** NOT updated fields, used for cache invalidation **/
    59→        userID: previousMetadata.userID, // not updated, used by cache strategy
    60→        startedAt: previousMetadata.startedAt, // not updated, used by cache strategy
    61→        slicesCacheStrategy: previousMetadata.slicesCacheStrategy, // not updated, used by cache strategy
    62→        sessionID: previousMetadata.sessionID, // not updated, used by cache strategy
    63→        /** Updated fields **/
    64→        updatedByActionType: originActionType,
    65→        changes: previousMetadata.changes + 1,
    66→        updatedAt: Date.now(),
    67→        ...override,
    68→      } satisfies MachineMetadata;
    69→
    70→      return {
    71→        ...state,
    72→        [METADATA_FIELD_NAME]: meta,
    73→      };
    74→    }
    75→
    76→    // Handling new state
    77→    // prettier-ignore
    78→    const slicesCacheStrategy = {} as MachineMetadata['slicesCacheStrategy'];
    79→
    80→    for (const { slice, sliceKey } of mappedSlices.info) {
    81→      slicesCacheStrategy[sliceKey] = slice.cache;
    82→    }
    83→
    84→    const { state, override } = operation;
    85→    const now = Date.now();
    86→
    87→    const metadata: MachineMetadata = {
    88→      userID,
    89→      updatedAt: now,
    90→      startedAt: now,
    91→      updatedByActionType: '',
    92→      changes: 0,
    93→      slicesCacheStrategy,
    94→      sessionID: currentSessionID,
    95→      ...override,
    96→    };
    97→
    98→    return {
    99→      ...state,
   100→      [METADATA_FIELD_NAME]: metadata,
   101→    };
   102→  }
   103→
   104→  export function RootReducer(params: {
   105→    mappedSlices: Slices.SlicesMap;
   106→    selectors: MachineSelectors<any> | undefined;
   107→    getContext: () => SliceContext;
   108→    getInitialState: () => MachineState;
   109→    machineID: string;
   110→    sessionID: string; // current sessionID
   111→    trackMetadata: boolean;
   112→  }): MachineReducer<any> {
   113→    const {
   114→      machineID,
   115→      getContext,
   116→      getInitialState,
   117→      selectors,
   118→      mappedSlices,
   119→      sessionID,
   120→      trackMetadata,
   121→    } = params;
   122→
   123→    const withSelectorValues = GetSelectorsWrapper({ selectors });
   124→
   125→    return function reducer(rootState = getInitialState(), action) {
   126→      if (action.type === `@@${machineID}/reset`) {
   127→        return action.payload;
   128→      }
   129→
   130→      // prettier-ignore
   131→      const reducer = mappedSlices.reducerByActionType[action.type as StringTypes.ActionType];
   132→
   133→      if (!reducer) {
   134→        return rootState;
   135→      }
   136→
   137→      const sliceKey = reducer.info.sliceKey;
   138→      const previousSliceState = rootState[sliceKey] as MachineState;
   139→      const nextSliceState = reducer(previousSliceState, action);
   140→
   141→      if (previousSliceState === nextSliceState) {
   142→        return rootState;
   143→      }
   144→
   145→      let next = {
   146→        ...rootState,
   147→        [sliceKey]: nextSliceState,
   148→      };
   149→
   150→      if (trackMetadata) {
   151→        next = UpsertStateMetadata({
   152→          currentSessionID: sessionID,
   153→          mappedSlices,
   154→          userID: getContext().userID,
   155→          operation: {
   156→            op: 'update',
   157→            state: next,
   158→            originActionType: action.type,
   159→            override: {},
   160→          },
   161→        });
   162→      }
   163→
   164→      return withSelectorValues(next);
   165→    };
   166→  }
   167→
   168→  /**
   169→   * Factory function to create a new state machine definition.
   170→   * @returns A frozen, read-only state machine definition object.
   171→   * @param config
   172→   */
   173→  export function Create<
   174→    const Slices extends MachineSlices,
   175→    const Selectors extends MachineSelectors<CombineSlicesState<Slices>>,
   176→    const State extends CombineSlicesState<Slices>,
   177→    const Context extends CombineSlicesContext<Slices>,
   178→    const ID extends string,
   179→  >(
   180→    config: MachineConfig<Slices, State, Selectors, Context, ID>,
   181→  ): StateMachine<Slices, State, Selectors, Context, ID> {
   182→    /**
   183→     * Internal values
   184→     */
   185→    const { id: ID, slices, sessionID: currentSessionID = GLOBAL_APP_SESSION_ID } = config;
   186→
   187→    const mappedSlices = Slices.MapSlices(ID, slices);
   188→
   189→    const context = Context.Handler({
   190→      ...mappedSlices.mergedSlicesInitialContext,
   191→      ...config.context,
   192→    });
   193→
   194→    let cacheInvalidationsReport: Cache.StateInvalidationsReport | null = null;
   195→
   196→    let initialState = (() => {
   197→      const { initial, selectors } = config;
   198→      const injectSelectorValues = GetSelectorsWrapper({ selectors });
   199→
   200→      const oldMetadata = initial?.[METADATA_FIELD_NAME];
   201→
   202→      let state = {
   203→        ...mappedSlices.mergedSlicesInitialState,
   204→        ...initial,
   205→      };
   206→
   207→      if (!oldMetadata) {
   208→        state = UpsertStateMetadata({
   209→          userID: config.context?.userID,
   210→          currentSessionID,
   211→          mappedSlices,
   212→          operation: {
   213→            op: 'create',
   214→            state,
   215→            override: {},
   216→          },
   217→        });
   218→        return injectSelectorValues(state);
   219→      }
   220→
   221→      cacheInvalidationsReport = Cache.StateInvalidations({
   222→        mappedSlices,
   223→        currentSessionID,
   224→        getContext: context.get,
   225→        cachedState: initial,
   226→        cachedMetadata: oldMetadata,
   227→      });
   228→
   229→      state = cacheInvalidationsReport.cleanState;
   230→
   231→      state = UpsertStateMetadata({
   232→        userID: config.context?.userID,
   233→        currentSessionID,
   234→        mappedSlices,
   235→        operation: {
   236→          op: 'update',
   237→          originActionType: `@@${ID}/remove_invalid_cache`,
   238→          state,
   239→          override: {},
   240→        },
   241→      });
   242→
   243→      return injectSelectorValues(state);
   244→    })();
   245→
   246→    const getInitialState = () => initialState;
   247→
   248→    const reducer = RootReducer({
   249→      machineID: ID,
   250→      selectors: config.selectors,
   251→      getInitialState,
   252→      getContext: context.get,
   253→      mappedSlices,
   254→      sessionID: currentSessionID,
   255→      trackMetadata: config.trackMetadata === true,
   256→    });
   257→
   258→    // prettier-ignore
   259→    const { actionCreatorsSliceKey, info, actionTypesBySliceKey } = mappedSlices;
   260→
   261→    type Machine = StateMachine<Slices, State, Selectors, Context, ID>;
   262→
   263→    const store = Store.create({
   264→      reducer,
   265→      getInitialState,
   266→      machineID: ID,
   267→    });
   268→
   269→    const stale = cacheInvalidationsReport?.stale.length
   270→      ? [...cacheInvalidationsReport.stale]
   271→      : null;
   272→
   273→    if (stale) {
   274→      let handled = false;
   275→      store.subscribe(() => {
   276→        if (handled) return;
   277→        handled = true;
   278→        store.dispatch({
   279→          type: `@@${ID}/refetch_stale_slices`,
   280→          payload: stale,
   281→        });
   282→        // biome-ignore lint/style/noNonNullAssertion: report is checked before this block
   283→        cacheInvalidationsReport!.stale.length = 0;
   284→      });
   285→    }
   286→
   287→    const { useMachine, useSelector } = Hooks({
   288→      mappedSlices: mappedSlices,
   289→      machineID: ID,
   290→      getContext: context.get,
   291→      store,
   292→    });
   293→
   294→    return {
   295→      ID,
   296→      config,
   297→      invalidations: cacheInvalidationsReport ?? null,
   298→      [`${ID}Reducer`]: reducer,
   299→      [`${ID}Actions`]: flatRecordRecords(ID, actionCreatorsSliceKey),
   300→      [`${ID}ActionTypes`]: flatRecordRecords(ID, actionTypesBySliceKey),
   301→      [`use${capitalize(ID)}`]: useMachine,
   302→      [`use${capitalize(ID)}Selector`]: useSelector,
   303→      useMachine,
   304→      useSelector,
   305→      mappedSlices: info,
   306→      reducer,
   307→      actions: actionCreatorsSliceKey,
   308→      actionTypes: actionTypesBySliceKey,
   309→      reset() {
   310→        store.dispatch({
   311→          type: `@@${ID}/reset`,
   312→          payload: getInitialState(),
   313→        });
   314→      },
   315→      subscribe(listener: Store.Listener<State>) {
   316→        return store.subscribe(listener as never);
   317→      },
   318→      getState() {
   319→        return store.getState();
   320→      },
   321→      dispatch(action: MachineAction) {
   322→        return store.dispatch(action);
   323→      },
   324→      getContext() {
   325→        return context.get() as Context;
   326→      },
   327→      getInitialState() {
   328→        return getInitialState();
   329→      },
   330→      provideContext(value: SliceContext) {
   331→        context.assign(value);
   332→        const metadata = initialState[METADATA_FIELD_NAME] as MachineMetadata;
   333→        assertObject(metadata, 'Metadata was not provided by initialState');
   334→        initialState = {
   335→          ...initialState,
   336→          [METADATA_FIELD_NAME]: {
   337→            ...metadata,
   338→            userID: context.get().userID,
   339→          },
   340→        };
   341→      },
   342→    } as Machine;
   343→  }
   344→}
   345→
   346→export const createMachine = Machine.Create;
   347→

