import type { Compute, Serializable, Writable } from '../../helpers/type-utils';
import type { CacheStrategy } from './cache';
import type { MachineState, SliceContext, SliceReducer } from './commons';

/** Represents the payload of a reducer action. Must be serializable. */
export type ActionPayload = Serializable;

/** Represents a generic Redux action. */
export type AnyAction = {
  type: string;
  [K: string]: any;
};

/** Distinguishes between synchronous and asynchronous slices. */
export enum SliceKind {
  async = 'async',
  sync = 'sync',
}

/** The reducers config expected by createSlice **/
export type SliceReducersConfig<State = any> = {
  [K: string]: SliceReducer<State, any>;
};

/**
 * Defines the structure of a synchronous slice, which manages a piece of state
 * through a set of reducer functions.
 */
export interface Slice<
  State extends MachineState,
  Reducers extends SliceReducersConfig<State>,
  ID extends string = string,
> {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind: SliceKind.sync;
  /** The initial state of the slice. */
  initial: State;
  /** A record of functions that can update the slice's state. */
  reducers: Reducers;
  /** Defines the caching behavior for the stored state **/
  cache: CacheStrategy;
}

/**
 * Defines the standard state shape for an asynchronous slice, tracking
 * loading status, data, and errors.
 */
export type AsyncSliceState<Value> = {
  loading: boolean;
  loaded: boolean;
  failed: boolean;
  error: string | null;
  value: Value | null;
  changes: number;
};

/**
 * Defines the structure of an asynchronous slice, which manages state
 * related to a data fetching operation.
 */
export interface AsyncSlice<
  Result,
  Payload extends ActionPayload,
  Context extends SliceContext,
  ID extends string = string,
> {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind: SliceKind.async;
  /** The function that performs the asynchronous operation. */
  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
  /** The runtime context required by the `load` function. */
  context: Context;
  /** The initial state shape for the async slice. */
  initial: AsyncSliceState<Result>;
  /** Defines the caching behavior for the stored state **/
  cache: CacheStrategy;
}

/** Configuration object for creating a synchronous slice. */
export type SliceConfig<
  State extends MachineState,
  Reducers extends SliceReducersConfig,
  ID extends string = string,
> = {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind?: SliceKind.sync;
  /** The initial state of the slice. */
  initial: State;
  /** A record of functions that can update the slice's state. */
  reducers: Reducers;
  /** Cache config for stored state */
  cache: CacheStrategy;
};

/** Configuration object for creating an asynchronous slice. */
export type AsyncSliceConfig<
  Payload extends ActionPayload,
  Result,
  Context extends SliceContext,
  ID extends string = string,
> = {
  /** A unique identifier for the slice within the machine. */
  id: ID;
  /** The kind of slice. */
  kind?: SliceKind.async;
  /** The function that performs the asynchronous operation. */
  load(payload: Payload, context: Compute<NoInfer<Context>>): Promise<Result>;
  /** The runtime context required by the `load` function. */
  context: Writable<Context>;
  /** The initial state shape for the async slice. */
  initial?: AsyncSliceState<Result>;
  cache: CacheStrategy;
};

/** Defines the signature of the `createSlice` factory function. */
export type CreateSlice = <
  State extends MachineState,
  const Reducers extends SliceReducersConfig<State>,
  const ID extends string,
>(
  config: SliceConfig<State, Reducers, ID>,
) => Slice<State, Reducers, ID>;

/** Defines the signature of the `createAsyncSlice` factory function. */
export type CreateAsyncSlice = <
  Payload extends ActionPayload,
  Result,
  const Context extends SliceContext,
  const ID extends string,
>(
  config: AsyncSliceConfig<Payload, Result, Context, ID>,
) => AsyncSlice<Result, Payload, Context, ID>;

# @belt/tools

A TypeScript utility library providing runtime type validation, state management, and common helpers.

## Installation

```bash
npm install @belt/tools
# or
pnpm add @belt/tools
```

**Peer Dependencies:**
- `react` >= 18.0.0 (optional, only for state-machine hooks)

## Features

- **Schema Validation** - Runtime type validation with TypeBox
- **State Machine** - Immer-based state management with React hooks
- **Helpers** - Common utilities (date, string, object, etc.)
- **Type Utilities** - Advanced TypeScript type helpers

---

## Quick Start

### Schema Validation

```tsx
import { createType, createModel, isType, InferType } from '@belt/tools';

// Create a validated model
const UserModel = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',        // optional
  roles: 'string[]',       // array
  createdAt: 'date',       // Date object
});

type User = InferType<typeof UserModel>;

// Parse and validate data
const user = UserModel.parse({
  id: 1,
  name: 'John',
  roles: ['admin'],
  createdAt: new Date(),
});

// Validation check
if (UserModel.isValid(someData)) {
  // TypeScript knows someData is User
}

// Complex type with nested objects
const GameStateType = createType({
  properties: {
    player: {
      properties: {
        position: { properties: { x: 'number', y: 'number', z: 'number' } },
        health: 'number',
        inventory: { items: 'string[]' },
      },
    },
    enemies: { items: { properties: { id: 'string', position: 'object' } } },
    score: 'number',
  },
});

// Type guard
if (isType(someValue, 'number')) {
  console.log(someValue.toFixed(2)); // TypeScript knows it's a number
}
```

### State Machine

```tsx
import { createMachine, createSlice, createAsyncSlice } from '@belt/tools';

// Sync slice for game state
const playerSlice = createSlice({
  id: 'player',
  initial: {
    position: { x: 0, y: 0, z: 0 },
    health: 100,
    score: 0,
  },
  cache: { policy: 'session' },
  reducers: {
    move: (state, delta: { x: number; y: number; z: number }) => {
      state.position.x += delta.x;
      state.position.y += delta.y;
      state.position.z += delta.z;
    },
    damage: (state, amount: number) => {
      state.health = Math.max(0, state.health - amount);
    },
    addScore: (state, points: number) => {
      state.score += points;
    },
  },
});

// Async slice for data fetching
const leaderboardSlice = createAsyncSlice({
  id: 'leaderboard',
  cache: { policy: 'public', ttl: '5m', swr: true },
  fetch: async () => {
    const response = await fetch('/api/leaderboard');
    return response.json();
  },
});

// Create the machine
const gameMachine = createMachine({
  id: 'game',
  slices: {
    player: playerSlice,
    leaderboard: leaderboardSlice,
  },
  context: { userID: null },
  trackMetadata: false, // Better performance
});

// Use in React components
function GameUI() {
  const { state, actions } = gameMachine.useMachine('player');

  // High-frequency updates are memoized - safe for 60fps
  return (
    <div>
      <span>Health: {state.health}</span>
      <span>Score: {state.score}</span>
    </div>
  );
}
```

### Helpers

```tsx
import {
  getProperty,
  setProperty,
  ms,
  formatDate,
  invariant,
  tryCatch,
  keyBy,
  compose,
} from '@belt/tools';

// Deep property access (type-safe)
const street = getProperty(user, 'address.street');

// Time conversion
const timeout = ms('5m');     // 300000 (5 minutes in ms)
const frame = ms('16ms');     // 16 (for 60fps)
const ttl = ms('1h');         // 3600000 (1 hour)

// Date formatting (uses date-fns)
const formatted = formatDate(new Date(), 'yyyy-MM-dd');

// Assertions
invariant(user.id, 'User ID is required');

// Safe error handling
const [error, result] = tryCatch(() => JSON.parse(data));

// Array to object by key
const usersById = keyBy(users, 'id');

// Function composition
const processData = compose(
  JSON.stringify,
  addMetadata,
  validate,
);
```

---

## Performance

### Configuration

```tsx
const gameMachine = createMachine({
  id: 'game',
  slices: { /* ... */ },
  context: { userID: null },

  // Disable metadata tracking for better performance
  trackMetadata: false,
});
```

### Game Loop Example

```tsx
import { createMachine, createSlice } from '@belt/tools';

// Game state slice
const gameSlice = createSlice({
  id: 'game',
  initial: {
    entities: new Map<string, Entity>(),
    camera: { x: 0, y: 0, zoom: 1 },
    frameCount: 0,
  },
  cache: { policy: 'session' },
  reducers: {
    updateEntity: (state, entity: Entity) => {
      state.entities.set(entity.id, entity);
    },
    updateCamera: (state, camera: Partial<typeof state.camera>) => {
      Object.assign(state.camera, camera);
    },
    tick: (state) => {
      state.frameCount += 1;
    },
  },
});

const machine = createMachine({
  id: 'webgl-game',
  slices: { game: gameSlice },
  context: { userID: null },
  trackMetadata: false,
});

// Game loop
function gameLoop() {
  const { state, actions } = machine.getState();

  // Process input
  processInput(actions);

  // Update physics
  updatePhysics(state.game.entities);

  // Dispatch tick (optimized - no array copy)
  actions.tick();

  // Render
  renderWebGL(state);

  requestAnimationFrame(gameLoop);
}
```

### Performance Optimizations Applied

| Area               | Optimization      | Benefit                   |
|--------------------|-------------------|---------------------------|
| Store listeners    | Reverse iteration | No array copy on dispatch |
| Hook results       | Memoized objects  | Prevents GC thrashing     |
| Schema cache       | 1h TTL            | Avoids recompilation      |
| Cache invalidation | Direct assignment | No temporary objects      |

---

## API Reference

### Schema Module

| Function                           | Description                           |
|------------------------------------|---------------------------------------|
| `createType(definition)`           | Create a runtime validation type      |
| `createModel(properties)`          | Shorthand for object type definitions |
| `isType(value, definition)`        | Type guard for validation             |
| `invariantType(definition, value)` | Assert value matches type             |

**Type Definition Syntax:**
- Primitives: `'string'`, `'number'`, `'boolean'`, `'date'`, `'null'`, `'undefined'`
- Optional: `'string?'`, `'number?'`
- Arrays: `'string[]'`, `'number[]'`
- Objects: `{ properties: { ... } }`
- Enums: `{ enum: ['a', 'b', 'c'] }`
- Unions: `{ union: ['string', 'number'] }`
- Records: `{ record: 'string' }`

### State Machine Module

| Function                   | Description                             |
|----------------------------|-----------------------------------------|
| `createMachine(config)`    | Create a state machine instance         |
| `createSlice(config)`      | Create a synchronous slice              |
| `createAsyncSlice(config)` | Create an async slice for data fetching |

**Cache Policies:**
- `public` - Shared cache, TTL-based invalidation
- `private` - User-specific cache
- `session` - Session-specific cache

**Machine Options:**
- `trackMetadata: false` - Disable for 60fps performance

### Helpers Module

| Function                        | Description                         |
|---------------------------------|-------------------------------------|
| `getProperty(obj, path)`        | Type-safe deep property access      |
| `setProperty(obj, path, value)` | Type-safe deep property setter      |
| `ms(timeString)`                | Convert time string to milliseconds |
| `formatDate(date, format)`      | Format date using date-fns          |
| `invariant(condition, message)` | Assert condition or throw           |
| `tryCatch(fn)`                  | Safe function execution             |
| `compose(...fns)`               | Right-to-left function composition  |
| `keyBy(array, key)`             | Convert array to object by key      |
| `maskData(value)`               | Mask sensitive data for logging     |

### Type Utilities

```tsx
import type {
  Writable,      // Remove readonly modifiers
  Compute,       // Flatten intersection types
  Paths,         // All dot-notation paths of object
  PathType,      // Type at specific path
  Falsy,         // Union of falsy values
  InferType,     // Infer type from schema definition
} from '@belt/tools';
```

---

