  id: 'game',
  slices: {
    player: playerSlice,
    leaderboard: leaderboardSlice,
  },
  context: { userID: null },
  trackMetadata: false, // Better performance
});

// Use in React components
function GameUI() {
  const { state, actions } = gameMachine.useMachine('player');

  // High-frequency updates are memoized - safe for 60fps
  return (
    <div>
      <span>Health: {state.health}</span>
      <span>Score: {state.score}</span>
    </div>
  );
}
```

