  ms,
  formatDate,
  invariant,
  tryCatch,
  keyBy,
  compose,
} from '@belt/tools';

// Deep property access (type-safe)
const street = getProperty(user, 'address.street');

// Time conversion
const timeout = ms('5m');     // 300000 (5 minutes in ms)
const frame = ms('16ms');     // 16 (for 60fps)
